import com.opengamma.strata.product.common.SummarizerUtils;

/**
 * A trade in a CDS index.
 * <p>
 * An Over-The-Counter (OTC) trade in a {@link CdsIndex}.
 * <p>
 * A CDS index is a portofolio of single name credit default swaps. 
 * The contract periodically pays fixed coupons to the index buyer until the expiry, 
 * and in return, the index buyer receives the bond of a defaulted constituent legal entity for par.  
 */
@BeanDefinition
public final class CdsIndexTrade
    implements ProductTrade, ResolvableTrade<ResolvedCdsIndexTrade>, ImmutableBean, Serializable {

  /**
   * The additional trade information, defaulted to an empty instance.
   * <p>
   * This allows additional information to be attached to the trade.
   */
  @PropertyDefinition(validate = "notNull", overrideGet = true)
  private final TradeInfo info;
  /**
   * The CDS index product that was agreed when the trade occurred.
   * <p>
   * The product captures the contracted financial details of the trade.
   */
  @PropertyDefinition(validate = "notNull", overrideGet = true)
  private final CdsIndex product;
  /**
   * The upfront fee of the product.
   * <p>
   * This specifies a single amount payable by the buyer to the seller.
   * Thus the sign must be compatible with the product Pay/Receive flag.
   * <p>
   * Some CDSs, especially legacy products, are traded at par and the upfront fee is not paid.
   */
  @PropertyDefinition(get = "optional")
  private final AdjustablePayment upfrontFee;

  //-------------------------------------------------------------------------
  @Override
  public CdsIndexTrade withInfo(PortfolioItemInfo info) {
    return new CdsIndexTrade(TradeInfo.from(info), product, upfrontFee);
  }

  //-------------------------------------------------------------------------
  @Override
  public PortfolioItemSummary summarize() {
    // 2Y Buy USD 1mm INDEX / 1.5% : 21Jan18-21Jan20
    PeriodicSchedule paymentSchedule = product.getPaymentSchedule();
    StringBuilder buf = new StringBuilder(96);
    buf.append(SummarizerUtils.datePeriod(paymentSchedule.getStartDate(), paymentSchedule.getEndDate()));
    buf.append(' ');
    buf.append(product.getBuySell());
    buf.append(' ');
    buf.append(SummarizerUtils.amount(product.getCurrency(), product.getNotional()));
    buf.append(' ');
    buf.append(product.getCdsIndexId().getValue());
    buf.append(" / ");
    buf.append(SummarizerUtils.percent(product.getFixedRate()));
    buf.append(" : ");
    buf.append(SummarizerUtils.dateRange(paymentSchedule.getStartDate(), paymentSchedule.getEndDate()));
