import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranche based on ISDA standard model.
 * <p>
 * The CDS tranche is priced using the underlying CDS index pricer with loss absorption
 * adjustments based on the tranche attachment and detachment points.
 * <p>
 * The present value is calculated as the expected loss for the tranche multiplied by
 * the underlying index's spread and notional.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The pricer for single name CDS index.
   */
  private final IsdaHomogenousCdsIndexProductPricer underlyingIndexPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.underlyingIndexPricer = new IsdaHomogenousCdsIndexProductPricer(formula);
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return underlyingIndexPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche.
   * <p>
   * The present value represents the value of the tranche from the protection buyer's perspective.
   * For the protection seller, the opposite sign should be used.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(refData, "refData");

    // Get the underlying index
    CurrencyAmount indexPv = underlyingIndexPricer.presentValue(
        cdsTranche.getUnderlyingIndex(),
        ratesProvider,
        referenceDate,
        refData);

    // Apply tranche adjustment based on loss absorption
    // The tranche receives protection only for losses between attachment and detachment points
    double trancheWidth = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();
    double adjustedPv = indexPv.getAmount() * trancheWidth;

    return indexPv.withAmount(adjustedPv);
  }

  /**
   * Calculates the present value sensitivity of the tranche.
   * <p>
   * The present value sensitivity of the tranche is the sensitivity of the present value
   * to the underlying credit curves.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivityBuilder presentValueSensitivity(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(refData, "refData");

    // Get the underlying index sensitivity
    PointSensitivityBuilder indexSensitivity = underlyingIndexPricer.presentValueSensitivity(
        cdsTranche.getUnderlyingIndex(),
        ratesProvider,
        referenceDate,
        refData);

    // Apply tranche adjustment
    double trancheWidth = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();
    return indexSensitivity.multipliedBy(trancheWidth);
  }

  /**
   * Calculates the price of the CDS tranche.
   * <p>
   * This method can calculate the clean or dirty price, see {@link PriceType}.
   * If calculating the clean price, the accrued interest is calculated based on the step-in date.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(priceType, "priceType");
    ArgChecker.notNull(refData, "refData");

    // Get the underlying index price
    double indexPrice = underlyingIndexPricer.price(
        cdsTranche.getUnderlyingIndex(),
        ratesProvider,
        referenceDate,
        priceType,
        refData);

    // Apply tranche adjustment
    double trancheWidth = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();
    return indexPrice * trancheWidth;
  }
}

